const input = $input.first()?.json || {};
const body = input.body || input;
const text = String(body.text || body.message || body.note || '').trim();
const now = new Date().toISOString();
const match = text.match(/(\d+(?:\.\d+)?)\s*(小時|hr|h|分鐘|分|min|m)/i);
const value = match ? Number(match[1]) : 0;
const unit = match ? match[2] : '';
const minutes = match ? (/(小時|hr|h)/i.test(unit) ? value * 60 : value) : 0;
const tagMatch = text.match(/#([\p{Script=Han}\w-]+)/u);
const category = tagMatch ? tagMatch[1] : (text.includes('閱讀') || text.toLowerCase().includes('learn') ? '學習' : '未分類');
const cleanActivity = text
  .replace(/\d+(?:\.\d+)?\s*(小時|hr|h|分鐘|分|min|m)/ig, '')
  .replace(/#[\p{Script=Han}\w-]+/gu, '')
  .trim() || '未命名活動';
return [{
  json: {
    raw_text: text,
    activity: cleanActivity,
    category,
    minutes,
    hours: Math.round((minutes / 60) * 100) / 100,
    started_at: body.started_at || now,
    source: body.source || 'demo-webhook',
    note: body.note || ''
  }
}];

const item = $input.first().json;
const minutes = Number(item.minutes || 0);
let quality = '待確認';
if (minutes >= 25 && minutes <= 120) quality = '有效專注';
if (minutes > 120) quality = '過長，建議拆段';
if (minutes > 0 && minutes < 25) quality = '短段紀錄';
return [{
  json: {
    ...item,
    quality,
    title: `${item.category} - ${item.activity}`.slice(0, 80),
    summary: `${item.activity}，${minutes || '?'} 分鐘，分類：${item.category}，判定：${quality}`
  }
}];
